function placeCard(
        GameTypes.RoomType roomType,
        uint16 roomId,
        uint8 x,
        uint8 y,
        uint8 cardIndex
    ) external override {
        _placeCard(msg.sender, roomType, roomId, x, y, cardIndex);
    }

